The _refresh may be triggered in any accessor of key_id, secret_key or security_token.
for instance, if client access those different parts crossing the point of expiration, the client would got wrong credentials eventually.

class RefreshableCredentials(Credentials):
    @property
    def access_key(self):
        self._refresh()
        return self._access_key

    @access_key.setter
    def access_key(self, value):
        self._access_key = value

    @property
    def secret_key(self):
        self._refresh()
        return self._secret_key

    @secret_key.setter
    def secret_key(self, value):
        self._secret_key = value

    @property
    def token(self):
        self._refresh()
        return self._token

    @token.setter
    def token(self, value):
        self._token = value

Am I missing something?

